The getToolPermission function is the single source of truth for all permission checks:
```ts
const getToolPermission = (state: ServerState, pluginName: string, toolName: string): ToolPermission => {
  if (state.skipPermissions) return 'auto';
  const pluginConfig = state.pluginPermissions[pluginName];
  if (!pluginConfig) return 'off';
  return pluginConfig.tools?.[toolName] ?? pluginConfig.permission ?? 'off';
};
```
